#__billiax-dashboard { background: linear-gradient(135deg, #0f172a, #1e293b); border: 1px solid rgba(99,102,241,0.2); border-radius: 12px; padding: 16px 20px; margin: 16px 0; font: 13px/1.4 -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; color: #cbd5e1; }
#__billiax-dashboard h2 { color: #e2e8f0; font-size: 16px; margin: 0 0 12px; display: flex; align-items: center; gap: 8px; }
#__billiax-dashboard h2 .accent { color: #818cf8; }
#__billiax-dashboard .repo-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 10px; }
#__billiax-dashboard .repo-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 10px; padding: 12px; transition: all 0.15s; text-decoration: none; color: inherit; display: block; }
#__billiax-dashboard .repo-card:hover { background: rgba(99,102,241,0.1); border-color: rgba(99,102,241,0.3); transform: translateY(-1px); }
#__billiax-dashboard .repo-name { color: #93c5fd; font-weight: 700; font-size: 13px; margin-bottom: 6px; }
#__billiax-dashboard .repo-lang { font-size: 11px; color: #64748b; }
#__billiax-dashboard .repo-lang .dot { display: inline-block; width: 8px; height: 8px; border-radius: 50%; margin-right: 4px; vertical-align: middle; }
#__billiax-dashboard .repo-stats { display: flex; gap: 10px; margin-top: 6px; font-size: 11px; color: #64748b; }
#__billiax-dashboard .repo-stats .stat { display: flex; align-items: center; gap: 3px; }
#__billiax-dashboard .repo-stats .hot { color: #f87171; font-weight: 600; }
#__billiax-dashboard .quick-row { display: flex; gap: 8px; margin-top: 14px; flex-wrap: wrap; }
#__billiax-dashboard .quick-btn { display: inline-flex; align-items: center; gap: 4px; padding: 6px 12px; border-radius: 8px; font-size: 12px; text-decoration: none; font-weight: 600; transition: all 0.15s; }
#__billiax-dashboard .quick-btn.primary { background: rgba(99,102,241,0.2); color: #a5b4fc; border: 1px solid rgba(99,102,241,0.3); }
#__billiax-dashboard .quick-btn.primary:hover { background: rgba(99,102,241,0.35); }
#__billiax-dashboard .quick-btn.success { background: rgba(34,197,94,0.15); color: #86efac; border: 1px solid rgba(34,197,94,0.25); }
#__billiax-dashboard .quick-btn.success:hover { background: rgba(34,197,94,0.3); }
#__billiax-dashboard .quick-btn.warn { background: rgba(245,158,11,0.15); color: #fcd34d; border: 1px solid rgba(245,158,11,0.25); }
#__billiax-dashboard .quick-btn.warn:hover { background: rgba(245,158,11,0.3); }
